commands.examples:
CREATE VIEW active_users AS
SELECT id, name, email FROM users WHERE active = true;

CREATE OR REPLACE VIEW order_summary AS
SELECT u.name, COUNT(o.id) AS total_orders, SUM(o.total) AS total_spent
FROM users u LEFT JOIN orders o ON u.id = o.user_id
GROUP BY u.name;

SELECT * FROM order_summary;

CREATE MATERIALIZED VIEW monthly_stats AS
SELECT DATE_TRUNC('month', created_at) AS month,
  COUNT(*) AS total, SUM(total) AS revenue
FROM orders GROUP BY 1;

-- Refresh data
REFRESH MATERIALIZED VIEW monthly_stats;
REFRESH MATERIALIZED VIEW CONCURRENTLY monthly_stats;

-- Index pada materialized view
CREATE UNIQUE INDEX idx_monthly ON monthly_stats (month);

DROP VIEW active_users;
DROP VIEW IF EXISTS order_summary CASCADE;
DROP MATERIALIZED VIEW IF EXISTS monthly_stats;
